changeSet.sql:
-- All passwords are pre-hashed with BCrypt cost 12 -- superadmin: ChangeMe!12345 -- testadmin: TestAdmin!12345 -- testmanager: TestManager!12345 -- testreceptionist: TestReceptionist!12345 -- teststaff: TestStaff!12345
INSERT INTO users (organization_id, username, email, password_hash, role_id, display_name, is_active, email_verified) SELECT o.id, 'superadmin', 'superadmin@lasema.test', '$2a$12$oc/zZUQy1PS6YZvMO/HxDOhafDn1Iv0eleMajMLVhiZe5clZ6xZhW', r.id, 'Super Admin', true, true FROM organizations o, roles r WHERE o.slug='lasema' AND r.code='SUPERADMIN' ON CONFLICT (username) DO NOTHING;
INSERT INTO users (organization_id, username, email, password_hash, role_id, display_name, is_active, email_verified) SELECT o.id, 'testadmin', 'testadmin@lasema.test', '$2a$12$eeJ/NcAMyOebL82HkGUN6.UbQw.pFZuByWmnxdMXS5.Sn3XHWUZwq', r.id, 'Test Admin', true, true FROM organizations o, roles r WHERE o.slug='lasema' AND r.code='ADMIN' ON CONFLICT (username) DO NOTHING;
INSERT INTO users (organization_id, username, email, password_hash, role_id, display_name, is_active, email_verified) SELECT o.id, 'testmanager', 'testmanager@lasema.test', '$2a$12$Lo3ajIeRN6T7QXYdMG2fGOortG1aDsccINiZqhSLatmlkbYrDu2sO', r.id, 'Test Manager', true, true FROM organizations o, roles r WHERE o.slug='lasema' AND r.code='MANAGER' ON CONFLICT (username) DO NOTHING;
INSERT INTO users (organization_id, username, email, password_hash, role_id, display_name, is_active, email_verified) SELECT o.id, 'testreceptionist', 'testreceptionist@lasema.test', '$2a$12$3Nie2ZHG7xs5w20oK7fB6uTyuCSCaFnqMmZteMMXp8kmq0Hzd4XMC', r.id, 'Test Receptionist', true, true FROM organizations o, roles r WHERE o.slug='lasema' AND r.code='RECEPTIONIST' ON CONFLICT (username) DO NOTHING;
INSERT INTO users (organization_id, username, email, password_hash, role_id, display_name, is_active, email_verified) SELECT o.id, 'teststaff', 'teststaff@lasema.test', '$2a$12$7X5frEh4/OM2Y5BpC00JT.c2I1e4p0JdD0tOhtahTnUdp1.Aes7ha', r.id, 'Test Staff', true, true FROM organizations o, roles r WHERE o.slug='lasema' AND r.code='STAFF' ON CONFLICT (username) DO NOTHING;
